if (! function_exists('data_heatmap')) {
    function data_heatmap($grid, $char_set = null)
    {
        if (empty($grid) || !is_array($grid)) {
            return json_encode(['error' => 'Grid must be a non-empty 2D array']);
        }

        $chars = isset($char_set) && strlen($char_set) > 1 ? $char_set : ' .:-=+*#%@';
        $numLevels = strlen($chars);

        // Find min and max across all values
        $allVals = [];
        foreach ($grid as $row) {
            if (!is_array($row)) continue;
            foreach ($row as $val) {
                if (is_numeric($val)) $allVals[] = (float)$val;
            }
        }

        if (empty($allVals)) {
            return json_encode(['error' => 'No numeric values found in grid']);
        }

        $min = min($allVals);
        $max = max($allVals);
        $range = $max - $min;

        $visualRows = [];
        foreach ($grid as $row) {
            $line = '';
            $rowVals = [];
            if (is_array($row)) {
                foreach ($row as $val) {
                    if (is_numeric($val)) {
                        $v = (float)$val;
                        $rowVals[] = $v;
                        $idx = $range > 0 ? (int)(($v - $min) / $range * ($numLevels - 1)) : 0;
                        $idx = max(0, min($numLevels - 1, $idx));
                        $line .= $chars[$idx];
                    } else {
                        $line .= '?';
                    }
                }
            }
            $visualRows[] = $line;
        }

        $output = implode("\n", $visualRows);
        return json_encode([
            'heatmap' => $output,
            'rows' => count($visualRows),
            'cols' => !empty($grid[0]) && is_array($grid[0]) ? count($grid[0]) : 0,
            'min' => $min,
            'max' => $max,
            'levels' => $numLevels,
            'char_set' => $chars
        ]);
    }
